const closing = ($('Extract Closing Data').item.json?.data || $('Extract Closing Data').item.json) || {};
const prevDocs = $('Get Previous Docs').all().map(r => r.json) || [];
const fileName = $('New Closing Doc').item.json.name;
const fileId   = $('New Closing Doc').item.json.id;

const c = v => parseFloat(String(v||0).replace(/[^0-9.]/g,'')) || 0;
const issues = (closing.validationIssuesList || '').split(';').filter(Boolean);
const missing = (closing.missingDocsList || '').split(';').filter(Boolean);

let validationFlags = [...issues];
if (closing.toleranceViolation) validationFlags.push('Tolerance violation: ' + (closing.toleranceDetails||''));
if (!closing.threeBusinessDayRule) validationFlags.push('3-business-day rule may not be met');
const cashToClose = c(closing.cashToClose);
const calcCash = c(closing.purchasePrice) - c(closing.loanAmount) - c(closing.sellerCredits) + c(closing.totalClosingCosts);
if (cashToClose > 0 && Math.abs(cashToClose - calcCash) > 100) validationFlags.push('Cash-to-close discrepancy');

const status = validationFlags.length === 0 ? 'Clear to Close' :
  validationFlags.some(f => f.includes('violation')) ? 'Hold' : 'Review Required';

return [{ json: {
  documentType:     closing.documentType     || 'N/A',
  propertyAddress: [closing.propertyStreet, closing.propertyCity, closing.propertyState, closing.propertyZip].filter(Boolean).join(', ') || closing.propertyAddress || 'N/A',
  closingDate:      closing.closingDate      || 'N/A',
  buyerName:        closing.buyerName        || 'N/A',
  sellerName:       closing.sellerName       || 'N/A',
  lenderName:       closing.lenderName       || 'N/A',
  purchasePrice:    c(closing.purchasePrice),
  loanAmount:       c(closing.loanAmount),
  loanType:         closing.loanType         || 'N/A',
  interestRate:     c(closing.interestRate),
  totalClosingCosts: c(closing.totalClosingCosts),
  cashToClose,
  validationFlags: validationFlags.join('; ') || 'None',
  flagCount: validationFlags.length,
  missingDocs: closing.missingDocsList || 'None',
  missingCount: missing.length,
  status,
  toleranceViolation: closing.toleranceViolation || false,
  prevDocCount: prevDocs.length,
  fileName, fileId,
  processedAt: new Date().toISOString(),
  fileId: fileId,
  fileNumber: "N/A",
  buyerNames: closing.buyerName || "N/A",
  sellerNames: closing.sellerName || "N/A",
  lender: closing.lenderName || "N/A",
  downPayment: c(closing.purchasePrice) - c(closing.loanAmount),
  totalBuyerCosts: c(closing.totalClosingCosts),
  totalSellerCosts: 0,
  proceedsToSeller: c(closing.sellerProceeds) || (c(closing.purchasePrice) - c(closing.loanAmount)),
  discrepancies: validationFlags.join("; ") || "None",
  validationStatus: status,
 relatedDocCount: prevDocs.length,
  signatures: "N/A",
}}];

